    `.trim(),toPlainText:l=>{const i=[];return l.titre_h1&&i.push(ft(l.titre_h1)),l.introduction&&i.push(ft(l.introduction)),(l.sections||[]).forEach(c=>{c.sous_titre_h2&&i.push(ft(c.sous_titre_h2)),c.contenu&&i.push(ft(c.contenu))}),l.conclusion&&i.push(ft(l.conclusion)),i.filter(Boolean).join(" ")}},i1={key:ve.SCRIPT_VIDEO_REEL_SHORT,shortKey:"Script Reel",storageField:"scriptVideo",editorTab:"atelier",promptTemplate:`
